const fs = require\('fs'\);
const path = require\('path'\);

function check\(jsxPath\) {
  const dir = path.dirname\(jsxPath\);
  const base = path.basename\(jsxPath, '.jsx'\);
  const cssPath = path.join\(dir, base + '.module.css'\);

  if \(!fs.existsSync\(cssPath\)\) {
    const jsx = fs.readFileSync\(jsxPath, 'utf8'\);
    const importMatch = jsx.match\(/from\\s+['"]\(.+\\.module\\.css\)['"]/\);
    if \(!importMatch\) {
      console.log\('NO CSS MODULE: ' + jsxPath\);
      return;
    }
    const resolvedCss = path.resolve\(dir, importMatch[1]\);
    if \(!fs.existsSync\(resolvedCss\)\) {
      console.log\('CSS NOT FOUND: ' + resolvedCss + ' \(from ' + jsxPath + '\)'\);
      return;
    }
    checkPair\(jsxPath, resolvedCss\);
    return;
  }
  checkPair\(jsxPath, cssPath\);
}

function checkPair\(jsxPath, cssPath\) {
  const jsx = fs.readFileSync\(jsxPath, 'utf8'\);
  const css = fs.readFileSync\(cssPath, 'utf8'\);

  // Extract styles.xxx from JSX
  const usedClasses = new Set\(\);
  const re = /styles\\.\(\\w+\)/g;
  let m;
  while \(\(m = re.exec\(jsx\)\) !== null\) {
    usedClasses.add\(m[1]\);
  }

  // Extract .xxx from CSS
  const definedClasses = new Set\(\);
  const cssRe = /\\.\([a-zA-Z_][\\w-]*\)\\s*[\\{,]/g;
  while \(\(m = cssRe.exec\(css\)\) !== null\) {
    definedClasses.add\(m[1]\);
  }

  // Check for missing
  const missing = [...usedClasses].filter\(c => !definedClasses.has\(c\)\);
  const unused = [...definedClasses].filter\(c => !usedClasses.has\(c\)\);

  if \(missing.length > 0 || unused.length > 0\) {
    console.log\('\\n=== ' + path.basename\(jsxPath\) + ' ==='\);
    if \(missing.length > 0\) {
      console.log\('  MISSING in CSS: ' + missing.join\(', '\)\);
    }
    if \(unused.length > 0\) {
      console.log\('  UNUSED in CSS: ' + unused.join\(', '\)\);
    }
  }
}

// Get all JSX files
const files = [];
const scanDir = \(d\) => {
  for \(const f of fs.readdirSync\(d\)\) {
    const fp = path.join\(d, f\);
    if \(fs.statSync\(fp\).isDirectory\(\)\) scanDir\(fp\);
    else if \(f.endsWith\('.jsx'\) && !f.includes\('.test.'\)\) files.push\(fp\);
  }
};
scanDir\('src/components'\);
files.push\('src/App.jsx'\);

for \(const f of files\) {
  check\(f\);
}

console.log\('\\nDone checking ' + files.length + ' files.'\);
